mapper.select:
select va.id, va.user_id, va.name , va.phone, va.apartment_id, va.appointment_time, va.additional_info, va.appointment_status, ai.id as ai_id, ai.name as ai_name, ai.introduction, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ai.address_detail, ai.latitude, ai.longitude, ai.phone as ai_phone, ai.is_release from view_appointment as va left join apartment_info as ai on va.apartment_id = ai.id and ai.is_deleted = 0
va.is_deleted = 0
and ai.province_id = #{queryVo.provinceId}
and ai.city_id = #{queryVo.cityId}
and ai.district_id = #{queryVo.districtId}
and va.apartment_id = #{queryVo.apartmentId}
and va.name like concat('%',#{queryVo.name},'%')
and va.phone like concat('%',#{queryVo.phone},'%')
